import base64
import zlib
import requests
from xml.etree.ElementTree import Element, SubElement, tostring
from xml.sax.saxutils import escape
from datetime import datetime
import uuid

def build_saml_request(destination_url, user_info):
    # Validate destination URL
    if not destination_url.startswith("https://"):
        raise ValueError("Invalid destination URL")

    # Validate user information
    if not isinstance(user_info, dict) or 'username' not in user_info:
        raise ValueError("Invalid user information")

    # Create SAML AuthnRequest
    authn_request = Element('samlp:AuthnRequest', {
        'xmlns:samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
        'ID': '_' + str(uuid.uuid4()),
        'Version': '2.0',
        'IssueInstant': datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ'),
        'Destination': escape(destination_url),
        'ProtocolBinding': 'urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST',
        'AssertionConsumerServiceURL': 'https://your-service-provider.com/acs'
    })

    issuer = SubElement(authn_request, 'saml:Issuer', {
        'xmlns:saml': 'urn:oasis:names:tc:SAML:2.0:assertion'
    })
    issuer.text = 'https://your-service-provider.com'

    name_id_policy = SubElement(authn_request, 'samlp:NameIDPolicy', {
        'Format': 'urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified',
        'AllowCreate': 'true'
    })

    # Convert XML to string
    saml_request_str = tostring(authn_request, encoding='unicode')

    # Compress and encode the SAML request
    deflated_request = zlib.compress(saml_request_str.encode('utf-8'))[2:-4]
    encoded_request = base64.b64encode(deflated_request).decode('utf-8')

    # Send the SAML request via POST
    response = requests.post(destination_url, data={'SAMLRequest': encoded_request})

    return response

# Example usage
destination = "https://idp.example.com/sso"
